        // If the user selects 'На складе' or 'Завершено'
        // the status will not be overridden
        return nextState;
    }

    if (debt > 0) {
        if (debt >= total) {
             nextState['Статус сделки'] = 'Без оплаты';
        } else {
             nextState['Статус сделки'] = 'Частичная оплата';
        }
    } else {
        // If debt is 0. 
        // If the calculated status would be partial/unpaid, fix it to Paid.
        // But if user selected 'На складе' or 'Завершено', keep it.
        const currentStatus = nextState['Статус сделки'];
        if (currentStatus === 'Частичная оплата' || currentStatus === 'Без оплаты') {
             nextState['Статус сделки'] = 'Оплачено';
        }
    }

    return nextState;
}
